// src/api/base.js

// Automatically switch between development and production

const DEV_API = "http://localhost:5000";

// When you deploy backend later,
// replace PROD_API with your real backend URL
const PROD_API = "https://your-backend-url.com";

export const API =
  process.env.NODE_ENV === "production"
    ? PROD_API
    : DEV_API;
